// Obtenemos la fecha de hoy y calculamos el viernes de esta semana
const hoy = new Date();
const finSemana = new Date(hoy);
finSemana.setDate(hoy.getDate() + (5 - hoy.getDay())); // Viernes

const reuniones = $input.all();
const reunionesSemana = [];

// Recorremos todas las reuniones y nos quedamos solo con las de esta semana
for (const item of reuniones) {
  // Convertimos la fecha del formato DD/MM/YYYY a un objeto Date
  const partes = item.json.fecha.split('/');
  const fechaReunion = new Date(partes[2], partes[1] - 1, partes[0]);

  if (fechaReunion >= hoy && fechaReunion <= finSemana) {
    reunionesSemana.push(item);
  }
}

// Si no hay reuniones esta semana, devolvemos un mensaje informativo
if (reunionesSemana.length === 0) {
  return [{ json: { hay_reuniones: false, resumen: 'No hay reuniones programadas esta semana.' } }];
}

// Construimos el resumen con formato legible
let resumen = 'Reuniones de esta semana:\n\n';
for (const r of reunionesSemana) {
  resumen += `- ${r.json.fecha} a las ${r.json.hora}\n`;
  resumen += `  Tipo: ${r.json.tipo_reunion}\n`;
  resumen += `  Lugar: ${r.json.ubicacion}\n`;
  resumen += `  Asistentes: ${r.json.asistentes}\n\n`;
}

return [{ json: { hay_reuniones: true, resumen: resumen, total: reunionesSemana.length } }];
